    }
    
    func logAuthenticationFlow(userID: String, email: String, token: String, status: String) {
        NSLog("Authentication Flow - UserID: \(userID), Email: \(email), Token: \(token), Status: \(status)")
        print("Authentication Flow - UserID: \(userID), Email: \(email), Token: \(token), Status: \(status)")
    }
    
    func logAPICall(endpoint: String, requestPayload: [String: Any], responsePayload: [String: Any], statusCode: Int) {
        NSLog("API Call - Endpoint: \(endpoint), Request: \(requestPayload), Response: \(responsePayload), Status Code: \(statusCode)")
        print("API Call - Endpoint: \(endpoint), Request: \(requestPayload), Response: \(responsePayload), Status Code: \(statusCode)")
    }
    
    func logUserDataChange(userID: String, email: String, changes: [String: Any]) {
        NSLog("User Data Change - UserID: \(userID), Email: \(email), Changes: \(changes)")
        print("User Data Change - UserID: \(userID), Email: \(email), Changes: \(changes)")
    }
    
    func logErrorCondition(userID: String?, email: String?, error: Error) {
